import {
  Empty,
  EmptyContent,
  EmptyDescription,
  EmptyHeader,
  EmptyTitle,
} from '@/components/ui/empty';
import {cn} from '@/lib/utils';

/**
 * Empty state for dark canvas surfaces. Thin wrapper around `Empty` that
 * applies `bg-canvas-bg` and removes the default dashed border so the
 * state blends into the topology canvas background.
 *
 * Re-exports EmptyHeader, EmptyTitle, EmptyDescription, EmptyContent
 * so callers only need one import.
 *
 * @example
 * <CanvasEmpty>
 *   <EmptyHeader>
 *     <EmptyTitle>No applications running</EmptyTitle>
 *     <EmptyDescription>
 *       Start a Compose project in your terminal and it will appear here.
 *     </EmptyDescription>
 *   </EmptyHeader>
 *   <EmptyContent>
 *     <Button>Get started</Button>
 *   </EmptyContent>
 * </CanvasEmpty>
 */
function CanvasEmpty({
  className,
  ...props
}: React.ComponentProps<typeof Empty>) {
  return (
    <Empty
      data-slot="canvas-empty"
      className={cn('border-0 bg-canvas-bg text-foreground', className)}
      {...props}
    />
  );
}

export {CanvasEmpty, EmptyHeader, EmptyTitle, EmptyDescription, EmptyContent};
